head.script:
scwin.initData = {
	"chart" : {
		"chartUnit" : 10,
		"chartIntervalCount" : 5,
		"acmtrtChartUnit" : 10,
		"acmtrtChartIntervalCount" : 3,
	},
	"observeEvent" : false
};

/**
 * 화면 초기화에 필요한 로직을 수행한다.
 * @param
 * @return
 */
scwin.initScreen = function() {
	// 화면초기화 공통 함수 호출
	comLib.initForm($p, "ECSCN5000000", {"initScreenCallback" : scwin.searchDatas});
};

/**
 * 화면 초기 데이터들을 조회한다.
 * @param
 * @return
 */
scwin.searchDatas = function() {
	// 조회조건 설정
	scwin.initSearchParam();
	// 화면 데이터 조회
	scwin.btnInqire_onclick();
};

/**
 * 조회조건 초기화에 필요한 로직을 수행한다.
 * @param
 * @return
 */
scwin.initSearchParam = function() {
	var strtDtM = utilLib.getCurrentDate("yyyyMM");
	var strtDtY = utilLib.getCurrentDate("yyyy");
	var basinCd = "ALL";

	var params = $p.getParameter("param");
	if (params) {
		if (params.type) {
			radYmBy.setValue(params.type);
			scwin.radYmBy_onviewchange();
		}
		if (params.year) {
			if (radYmBy.getValue() == "M") {
				if (params.month) {
					strtDtM = String(params.year) + String(params.month);
				} else {
					if (strtDtM.substr(0, 4) == params.year) {
						strtDtM = String(params.year) + strtDtM.substr(4, 2);
					} else {
						strtDtM = String(params.year) + "12";
					}
				}
			} else {
				strtDtY = String(params.year);
			}
		}
		if (params.basinCd) {
			basinCd = params.basinCd;
			acbBasin.setValue(basinCd);
		}
	}

	dmaSearchParam.set("strtDtM", strtDtM);
	dmaSearchParam.set("strtDtY", strtDtY);
	dmaSearchParam.set("basinCd", basinCd);
	dmaSearchParam.set("deptCd", "ALL");
	dmaSearchParam.set("cnstnCd", "ALL");
};

/**
 * 조회조건에 맞게 data를 조회한다.
 * @param
 * @return
 */
scwin.btnInqire_onclick = function() {
	var cnd = radYmBy.getValue();

	if (cnd == "M") {
		var strtDate = dmaSearchParam.get("strtDtM");
		var endDate = strtDate
		var cnd = "mnby";

		if (String(strtDate).length != 6) {
			// 조회기간이 올바르지 않습니다.
			alert(utilLib.getMessage("ECS.INFO.00011")[0]);
			return;
		}
	} else if (cnd == "Y") {
		var strtDate = dmaSearchParam.get("strtDtY");
		var endDate = strtDate
		var cnd = "yyby";

		if (String(strtDate).length != 4) {
			// 조회기간이 올바르지 않습니다.
			alert(utilLib.getMessage("ECS.INFO.00011")[0]);
			return;
		}
	}

	var ecsBasinDivCd = dmaSearchParam.get("basinCd");
	var ecsChrgDeptId = dmaSearchParam.get("deptCd");
	var ecsCnstscDivCd = dmaSearchParam.get("cnstnCd");

	var queryString = `?strtDt=${strtDate}`;
	queryString += `&endDt=${strtDate}`;
	queryString += `&cnd=${cnd}`;
	queryString += `&ecsBasinDivCd=${ecsBasinDivCd}`;
	queryString += `&ecsChrgDeptId=${ecsChrgDeptId}`;
	queryString += `&ecsCnstscDivCd=${ecsCnstscDivCd}`;

	var option = {
		action : "cn/epbusttus/retrieve-epbu-sttus.do"
			+ queryString,
		method : "get",
		resData : dltEpbuSttusList,
		success : "scwin.inqireCallback",
		isShowMeg : false
	};
	ajaxLib.executeAjax($p, option);
};

/**
 * 조회 CallBack 실행한다.
 * @param
 * @return
 */
scwin.inqireCallback = function() {
	var dltData = dltEpbuSttusList.getAllJSON();
	// 전력원단위 차트  생성_231025
	scwin.setEpbuChart();
	// 수요거래 정산금 차트  생성_240118
	scwin.setExcclcAmtChart();
	// 소내소비용 태양광 발전량 차트  생성_240118
	scwin.setSnpwElyrsChart();

	if (dltEpbuSttusList.getRowCount()) {
		// 조회된 값에 권한ID가 비어있지 않으면 읽기 속성으로 비어 있으면 쓰기 로 설정 변경
		for (var i = 0; i < dltEpbuSttusList.getRowCount(); i++) {
			if (i < 7) {
				grdEpbuSttusList.setRowReadOnly(i, true);
			} else {
				grdEpbuSttusList.setCellReadOnly(i, "btnSeq", true);
			}
		}

		/*
		// 틀고정
		if (dltData[0].basinNm.includes("전 체 합 계")) {
			//var color = "RGB(228, 238, 255)";
			//grdEpbuSttusList.setRowBackgroundColor(0, color);
			grdEpbuSttusList.setFixedRow(1);
			grdEpbuSttusList.mergeCellsFixedRows("byrow");
			document.querySelector(".w2grid_fixedRow").style.borderBottom = '2px solid #ADADAD';
		} else if (!dltData[0].basinNm.includes("전 체 합 계")) {
			document.querySelector(".w2grid_fixedRow").style.borderBottom = '1px solid #DADADA';
			grdEpbuSttusList.setFixedRow("");
			grdEpbuSttusList.mergeCellsFixedRows("never");
		}
		*/

		var lastIdxData = dltData.splice(-1)[0];

		grdEpbuSttusList.setFooterData("fBasinNm", lastIdxData.bplcNm);
		grdEpbuSttusList.setFooterData("fUswtrSqty", lastIdxData.uswtrSqty);
		grdEpbuSttusList.setFooterData("fEpwrUsgqty", lastIdxData.epwrUsgqty);
		grdEpbuSttusList.setFooterData("fKepcoNticCg", lastIdxData.kepcoNticCg);
		grdEpbuSttusList.setFooterData("fExcclcAmt", lastIdxData.excclcAmt);
		grdEpbuSttusList.setFooterData("fEpbu", scwin.dsplFrmt(lastIdxData.epbu));
		grdEpbuSttusList.setFooterData("fSnpwElyrs", lastIdxData.snpwElyrs);
		dltEpbuSttusList.setJSON(dltData);
	}
};

scwin.acbBasin_onviewchange = function(info) {
	var ecsBasinDivCd = info.newValue;
	dmaSearchParam.set("basinCd", ecsBasinDivCd);

	var queryString = `?ecsBasinDivCd=${ecsBasinDivCd}`;
	var option = {
		action : "zz/cmmn/retrieve-cnsmp-sttus-cnd-kepco-dept.do"
			+ queryString,
		method : "get",
		resData : dltAutoCondition2,
		success : "",
		isShowMeg : false
	};
	ajaxLib.executeAjax($p, option);
	dmaSearchParam.set("deptCd", "ALL");
};

scwin.acbDept_onviewchange = function(info) {
	dmaSearchParam.set("deptCd", info.newValue);
};

scwin.acbCnstn_onviewchange = function(info) {
	dmaSearchParam.set("cnstnCd", info.newValue);
};

/**
 * 라디오버튼 선택에 따라 조회연도를 변경한다.
 * @param
 * @return
 */
scwin.radYmBy_onviewchange = function() {
	var cnd = radYmBy.getValue();

	if (cnd == "M") {
		grpCalMNm.setStyle("display", "");
		grpCalMBox.setStyle("display", "");
		grpCalYNm.setStyle("display", "none");
		grpCalYBox.setStyle("display", "none");
	} else if (cnd == "Y") {
		grpCalYNm.setStyle("display", "");
		grpCalYBox.setStyle("display", "");
		grpCalMNm.setStyle("display", "none");
		grpCalMBox.setStyle("display", "none");
	} else {
		return;
	}
};

//============================================================================================
// 차트
//============================================================================================
/**
 * 전력원단위 차트 생성_231025
 */
scwin.setEpbuChart = function() {
	var chartVars = "rMateOnLoadCallFunction=" + $p.id + "scwin.chartReadyHandlerEpbu";
	rMateChartH5.create($p.id + "chartEpbu", grpChartEpbu.getID(), chartVars, "100%", "100%");
};

/**
* 전력원단위 차트 설정_231025
*/
scwin.chartReadyHandlerEpbu = function(id) {
	var epbuSttusData = dltEpbuSttusList.getAllJSON();
	var nameList = dltAutoCondition1.getAllJSON();
	var ecsBasinDivCd = dmaSearchParam.get("basinCd");
	var ecsChrgDeptId = dmaSearchParam.get("deptCd");
	var chartData = [];

	if (ecsChrgDeptId == "ALL") {
		var bplcNm = epbuSttusData.filter(obj => obj.bplcNm == "유 역 합 계");
		if (ecsBasinDivCd == "ALL") {
			var name = nameList.map(obj => obj.cmmnCdNm);
			name.forEach(prefix => {
				var epbu = 0;
				var basinNm = "";
				// 유역이 없어도 차트에 이름을 추가하기 위해 for문 추가_240118
				for (var idx = 0; idx < bplcNm.length; idx++) {
					if (bplcNm[idx].basinNm.includes(prefix)) {
						bplcNm.forEach(obj => {
							if (obj.basinNm.startsWith(prefix)) {
								epbu = obj.epbu;
								basinNm = prefix;
							}
						});
					} else if (!bplcNm[idx].basinNm.includes(prefix)) {
						if (basinNm == "") {
							epbu = 0;
							basinNm = prefix;
						}
					}
				}
				chartData.push({"Name" : basinNm, "Epbu" : epbu});
			});
		} else {
			var bplcNm = epbuSttusData.filter(obj => obj.bplcNm == "합 계");
			bplcNm.forEach(obj => {
				chartData.push({"Name" : obj.deptNm, "Epbu" : obj.epbu});
			});
		}
	} else {
		var bplcNm = epbuSttusData.filter(obj => obj.bplcNm != "합 계");
		bplcNm.forEach(obj => {
			chartData.push({"Name" : obj.bplcNm, "Epbu" : obj.epbu});
		});
	}

	var maxData = chartData.reduce((max, obj) => Math.max(max, obj.Epbu), 0);
	var chartUnit = Math.max(1, Math.pow(10, String(maxData.toFixed(0)).length - 2));
	var interval = Math.ceil((maxData / scwin.initData.chart.chartIntervalCount) / chartUnit) * chartUnit;

	var layoutStr =
		'<rMateChart backgroundColor="#FFFFFF" cornerRadius="12">'
		+ '	<Options>'
		+ '		<Caption text="전력원단위" textAlign="center" paddingTop="4.8" paddingRight="3.2" paddingBottom="4.8" paddingLeft="9.6" fontWeight="bold" fontSize="1rem" />'
		+ '		<Legend />'
		+ '	</Options>'
		+ '	<NumberFormatter id="numFmt" useThousandsSeparator="true" />'
		+ '	<Column2DChart showDataTips="true" type="clustered" dataTipDisplayMode="axis" maxColumnWidth="25">'
		+ '		<horizontalAxis>'
		+ '			<CategoryAxis id="hAxis" categoryField="Name" padding="0.7" />'
		+ '		</horizontalAxis>'
		+ '		<verticalAxis>'
		+ '			<LinearAxis id="vAxis1" interval="' + interval + '" formatter="{numFmt}" title="kWh/㎥"/>'
		+ '		</verticalAxis>'
		+ '		<series>'
		+ '			<Column2DSeries color="#666666" labelPosition="outside" fontWeight="bold" yField="Epbu" displayName="전력원단위(kWh/㎥)">'
		+ '				<fill>'
		+ '					<SolidColor color="#30A744" />'
		+ '				</fill>'
		+ '				<showDataEffect>'
		+ '					<SeriesInterpolate />'
		+ '				</showDataEffect>'
		+ '			</Column2DSeries>'
		+ '		</series>'
		+ '		<verticalAxisRenderers>'
		+ '			<Axis2DRenderer axis="{vAxis1}" verticalAxisTitleAlignment="vertical" showLine="false" />'
		+ '		</verticalAxisRenderers>'
		+ '	<horizontalAxisRenderers>'
		+ '		<Axis2DRenderer axis="{hAxis}" showLine="true" labelRotation="45" canDropLabels="false" canStagger="true"/>'
		+ '	</horizontalAxisRenderers>'
		+ '	</Column2DChart>'
		+ '</rMateChart>';

	document.getElementById(id).setLayout(layoutStr);
	document.getElementById(id).setData(chartData);
};

/**
 * 수요거래 정산금 차트 생성_240118
 */
scwin.setExcclcAmtChart = function() {
	var chartVars = "rMateOnLoadCallFunction=" + $p.id + "scwin.chartReadyHandlerExcclcAmt";
	rMateChartH5.create($p.id + "chartExcclcAmt", grpChartExcclcAmt.getID(), chartVars, "100%", "100%");
};

/**
* 수요거래 정산금 차트 설정_240118
*/
scwin.chartReadyHandlerExcclcAmt = function(id) {
	var epbuSttusData = dltEpbuSttusList.getAllJSON();
	var source = id.split("_");
	var chartNm = source[source.length - 1];
	var nameList = dltAutoCondition1.getAllJSON();
	var ecsBasinDivCd = dmaSearchParam.get("basinCd");
	var ecsChrgDeptId = dmaSearchParam.get("deptCd");
	var chartData = [];

	if (ecsChrgDeptId == "ALL") {
		var bplcNm = epbuSttusData.filter(obj => obj.bplcNm == "유 역 합 계");
		if (ecsBasinDivCd == "ALL") {
			var name = nameList.map(obj => obj.cmmnCdNm);
			name.forEach(prefix => {
				var excclcAmt = 0;
				var basinNm = "";
				// 유역이 없어도 차트에 이름을 추가하기 위해 for문 추가_240118
				for (var idx = 0; idx < bplcNm.length; idx++) {
					if (bplcNm[idx].basinNm.includes(prefix)) {
						bplcNm.forEach(obj => {
							if (obj.basinNm.startsWith(prefix)) {
								excclcAmt = obj.excclcAmt;
								basinNm = prefix;
							}
						});
					} else if (!bplcNm[idx].basinNm.includes(prefix)) {
						if (basinNm == "") {
							excclcAmt = 0;
							basinNm = prefix;
						}
					}
				}
				var value = Number(ecsLib.dsplZeroFrmt(excclcAmt / 1000 / 1000, 0).replaceAll(",", "")) || 0;
				chartData.push({"Name" : basinNm, "Data" : value});
			});
		} else {
			var bplcNm = epbuSttusData.filter(obj => obj.bplcNm == "합 계");
			bplcNm.forEach(obj => {
				var value = Number(ecsLib.dsplZeroFrmt(obj.excclcAmt / 1000 / 1000, 0).replaceAll(",", "")) || 0;
				chartData.push({"Name" : obj.deptNm, "Data" : value});
			});
		}
	} else {
		var bplcNm = epbuSttusData.filter(obj => obj.bplcNm != "합 계");
		bplcNm.forEach(obj => {
			var value = Number(ecsLib.dsplZeroFrmt(obj.excclcAmt / 1000 / 1000, 0).replaceAll(",", "")) || 0;
			chartData.push({"Name" : obj.bplcNm, "Data" : value});
		});
	}

	var maxData = chartData.reduce((max, obj) => Math.max(max, obj.Data), 0);
	var chartUnit = Math.max(scwin.initData.chart.chartUnit, Math.pow(10, String(maxData.toFixed(0)).length - 2));
	var interval = Math.ceil((maxData / scwin.initData.chart.chartIntervalCount) / chartUnit) * chartUnit;

	var solidColor = ecsLib.getSkinColors().chartSolidColor1;

	var layoutStr =
		'<rMateChart backgroundColor="#FFFFFF" cornerRadius="12">'
		+ '	<Options>'
		+ '		<Caption text="수요거래 정산금" textAlign="center" paddingTop="4.8" paddingRight="3.2" paddingBottom="4.8" paddingLeft="9.6" fontWeight="bold" fontSize="1rem" />'
		+ '		<Legend />'
		+ '	</Options>'
		+ '	<NumberFormatter id="numFmt" useThousandsSeparator="true" />'
		+ '	<Column2DChart showDataTips="true" dataTipDisplayMode="axis" maxColumnWidth="25">'
		+ '		<horizontalAxis>'
		+ '			<CategoryAxis id="hAxis" categoryField="Name" />'
		+ '		</horizontalAxis>'
		+ '		<verticalAxis>'
		+ '			<LinearAxis id="vAxis" interval="' + interval + '" formatter="{numFmt}" title="백만"/>'
		+ '		</verticalAxis>'
		+ '		<series>'
		+ '			<Column2DSeries color="#666666" labelPosition="outside" fontWeight="bold" displayName="정산금(백만)" yField="Data">'
		+ '				<fill>'
		+ '					<SolidColor color="' + solidColor + '" />'
		+ '				</fill>'
		+ '				<showDataEffect>'
		+ '					<SeriesInterpolate />'
		+ '				</showDataEffect>'
		+ '			</Column2DSeries>'
		+ '			</series>'
		+ '		<verticalAxisRenderers>'
		+ '			<Axis2DRenderer axis="{vAxis}" verticalAxisTitleAlignment="vertical" showLine="false" />'
		+ '		</verticalAxisRenderers>'
		+ '	<horizontalAxisRenderers>'
		+ '		<Axis2DRenderer axis="{hAxis}" showLine="true" labelRotation="45" canDropLabels="false" canStagger="true"/>'
		+ '	</horizontalAxisRenderers>'
		+ '	</Column2DChart>'
		+ '</rMateChart>';

	document.getElementById(id).setLayout(layoutStr);
	document.getElementById(id).setData(chartData);
};

/**
 * 소내소비용 태양광 발전량 차트 생성_240118
 */
scwin.setSnpwElyrsChart = function() {
	var chartVars = "rMateOnLoadCallFunction=" + $p.id + "scwin.chartReadyHandlerSnpwElyrs";
	rMateChartH5.create($p.id + "chartSnpwElyrs", grpChartSnpwElyrs.getID(), chartVars, "100%", "100%");
};

/**
* 소내소비용 태양광 발전량 차트 설정_240118
*/
scwin.chartReadyHandlerSnpwElyrs = function(id) {
	var epbuSttusData = dltEpbuSttusList.getAllJSON();
	var source = id.split("_");
	var chartNm = source[source.length - 1];
	var nameList = dltAutoCondition1.getAllJSON();
	var ecsBasinDivCd = dmaSearchParam.get("basinCd");
	var ecsChrgDeptId = dmaSearchParam.get("deptCd");
	var chartData = [];

	if (ecsChrgDeptId == "ALL") {
		var bplcNm = epbuSttusData.filter(obj => obj.bplcNm == "유 역 합 계");
		if (ecsBasinDivCd == "ALL") {
			var name = nameList.map(obj => obj.cmmnCdNm);
			name.forEach(prefix => {
				var snpwElyrs = 0;
				var basinNm = "";
				// 유역이 없어도 차트에 이름을 추가하기 위해 for문 추가_240118 
				for (var idx = 0; idx < bplcNm.length; idx++) {
					if (bplcNm[idx].basinNm.includes(prefix)) {
						bplcNm.forEach(obj => {
							if (obj.basinNm.startsWith(prefix)) {
								snpwElyrs = obj.snpwElyrs;
								basinNm = prefix;
							}
						});
					} else if (!bplcNm[idx].basinNm.includes(prefix)) {
						if (basinNm == "") {
							snpwElyrs = 0;
							basinNm = prefix;
						}
					}
				}
				chartData.push({"Name" : basinNm, "Data" : Number(ecsLib.dsplZeroFrmt(snpwElyrs, 0).replaceAll(",", ""))});
			});
		} else {
			var bplcNm = epbuSttusData.filter(obj => obj.bplcNm == "합 계");
			bplcNm.forEach(obj => {
				chartData.push({"Name" : obj.deptNm, "Data" : Number(ecsLib.dsplZeroFrmt(obj.snpwElyrs, 0).replaceAll(",", ""))});
			});
		}
	} else {
		var bplcNm = epbuSttusData.filter(obj => obj.bplcNm != "합 계");
		bplcNm.forEach(obj => {
			chartData.push({"Name" : obj.bplcNm, "Data" : Number(ecsLib.dsplZeroFrmt(obj.snpwElyrs, 0).replaceAll(",", ""))});
		});
	}

	var maxData = chartData.reduce((max, obj) => Math.max(max, obj.Data), 0);
	var chartUnit = Math.max(scwin.initData.chart.chartUnit, Math.pow(10, String(maxData.toFixed(0)).length - 2));
	var interval = Math.ceil((maxData / scwin.initData.chart.chartIntervalCount) / chartUnit) * chartUnit;

	var solidColor = ecsLib.getSkinColors().chartSolidColor1;

	var layoutStr =
		'<rMateChart backgroundColor="#FFFFFF" cornerRadius="12">'
		+ '	<Options>'
		+ '		<Caption text="소내소비용 태양광 발전량" textAlign="center" paddingTop="4.8" paddingRight="3.2" paddingBottom="4.8" paddingLeft="9.6" fontWeight="bold" fontSize="1rem" />'
		+ '		<Legend />'
		+ '	</Options>'
		+ '	<NumberFormatter id="numFmt" useThousandsSeparator="true" />'
		+ '	<Column2DChart showDataTips="true" dataTipDisplayMode="axis" maxColumnWidth="25">'
		+ '		<horizontalAxis>'
		+ '			<CategoryAxis id="hAxis" categoryField="Name" />'
		+ '		</horizontalAxis>'
		+ '		<verticalAxis>'
		+ '			<LinearAxis id="vAxis" interval="' + interval + '" formatter="{numFmt}" title="kWh"/>'
		+ '		</verticalAxis>'
		+ '		<series>'
		+ '			<Column2DSeries color="#666666" labelPosition="outside" fontWeight="bold" displayName="발전량(kWh)" yField="Data">'
		+ '				<fill>'
		+ '					<SolidColor color="' + solidColor + '" />'
		+ '				</fill>'
		+ '				<showDataEffect>'
		+ '					<SeriesInterpolate />'
		+ '				</showDataEffect>'
		+ '			</Column2DSeries>'
		+ '			</series>'
		+ '		<verticalAxisRenderers>'
		+ '			<Axis2DRenderer axis="{vAxis}" verticalAxisTitleAlignment="vertical" showLine="false" />'
		+ '		</verticalAxisRenderers>'
		+ '	<horizontalAxisRenderers>'
		+ '		<Axis2DRenderer axis="{hAxis}" showLine="true" labelRotation="45" canDropLabels="false" canStagger="true"/>'
		+ '	</horizontalAxisRenderers>'
		+ '	</Column2DChart>'
		+ '</rMateChart>';

	document.getElementById(id).setLayout(layoutStr);
	document.getElementById(id).setData(chartData);
};

/**
 * 그리드 소수점 4자리까지 표시 한다.
 * @param value
 * @return
 */
scwin.dsplFrmt = function(value) {
	return ecsLib.dsplZeroFrmt(value, 4);
};

/**
 * 그리드 소수점을 제거 한다.
 * @param value
 * @return
 */
scwin.dsplZeroFrmt = function(value) {
	return ecsLib.dsplZeroFrmt(value, 0);
};

//============================================================================================
// 엑셀
//============================================================================================
/**
 * 그리드의 내용을 엑셀로 다운로드 한다.
 * @return
 */
scwin.btnDownExcel_onclick = function() {
	var menuNm = $p.getComponentById("wfm_title").scope.$p.getComponentById("tbxScreenTitle").getValue();
	// 엑셀 내부 타이틀 추가_240105
	var infoArr = [];
	var infoObj = {
		rowIndex 	: 0,
		colIndex 	: 0,
		rowSpan 	: 0,
		colSpan 	: 10,
		text 		: `${menuNm}`,
		textAlign 	: "left"
	};
	infoArr.push(infoObj);

	comLib.downloadExcel(grdEpbuSttusList, {
		fileName : `${menuNm}.xlsx`,
		type : 1,
		autoSizeColumn : true,
		colMerge : true,
		colMergeValue : true,
		mergeCell : true,
		useDataFormat: true,
		applyDataFormat : true,
		decimal : "auto"
	}, infoArr);
};
